class SendgridMailer < ApplicationMailer
  default from: -> { default_from_address }

  def send_email(to:, subject:, html: nil, text: nil, from: nil, reply_to: nil, cc: nil, bcc: nil, attachments: [])
    @to = Array(to)
    @subject = subject.to_s
    @html = html
    @text = text
    @from = (from.presence || default_from_address).to_s
    @reply_to = reply_to
    @cc = Array(cc).presence
    @bcc = Array(bcc).presence
    @attachments = attachments

    message = mail(
      to: @to,
      from: @from,
      subject: @subject,
      reply_to: @reply_to,
      cc: @cc,
      bcc: @bcc
    ) do |format|
      format.html { render html: @html.html_safe, layout: false } if @html.present?
      format.text { render plain: @text } if @text.present?
    end

    attach_files(message, @attachments)

    message
  end

  private

  def default_from_address
    Rails.application.credentials.dig(:sendgrid, :from) ||
      ENV["SENDGRID_FROM"] ||
      "no-reply@#{default_domain}"
  end

  def default_domain
    ENV["APP_DOMAIN"] || "example.com"
  end

  def attach_files(message, attachments_list)
    Array(attachments_list).each do |att|
      next if att.blank?

      filename = att[:filename] || att["filename"]
      content = att[:content] || att["content"]
      mime_type = att[:type] || att["type"]

      if att[:path] || att["path"]
        path = att[:path] || att["path"]
        message.attachments[filename || File.basename(path)] = File.read(path)
      elsif content
        message.attachments[filename || "attachment"] = { mime_type: mime_type, content: content }
      end
    end
  end
